public extension ColorToken {
    func token(for subtheme: Subtheme) -> ColorToken {
        let identifier = self.tokenIdentifier(for: subtheme)
        guard let color = Colors(rawValue: identifier) else {
            return self
        }
        return color.token
    }
}

